// Faktisk Studio · Pop up-plugin
// Bilde med lys grå ramme — klikk åpner stort i lightbox med caption + kreditt + X-knapp.

const PLUGIN_ID = 'pop-up';

// Vis app-versjon + plugin-versjon i topp-bar
(async () => {
  try {
    const [appV, plugins] = await Promise.all([
      window.faktisk.appVersion(),
      window.faktisk.pluginStatus(),
    ]);
    const me = (plugins || []).find(p => p.id === PLUGIN_ID);
    const el = document.getElementById('appVersion');
    if (el && appV) {
      el.textContent = me ? 'v' + appV + ' · plugin v' + me.version : 'v' + appV;
    }
  } catch (e) {}
})();

const els = {
  modeSingleBtn: document.getElementById('modeSingleBtn'),
  modeGalleryBtn: document.getElementById('modeGalleryBtn'),
  imagesLabel:   document.getElementById('imagesLabel'),
  addImageBtn:   document.getElementById('addImageBtn'),
  imageList:     document.getElementById('imageList'),
  galleryHint:   document.getElementById('galleryHint'),
  photographer:  document.getElementById('photographerText'),
  status:        document.getElementById('status'),
  emptyState:    document.getElementById('emptyState'),
  preview:       document.getElementById('preview'),
  copyEmbed:     document.getElementById('copyEmbedBtn'),
  back:          document.getElementById('backBtn'),
  full:          document.getElementById('fullscreenBtn'),
  openLabrador:  document.getElementById('openLabradorBtn'),
  projectSelect: document.getElementById('projectSelect'),
  saveProject:   document.getElementById('saveProjectBtn'),
};

const state = {
  mode: 'single',                        // 'single' | 'gallery'
  images: [{ url: '', caption: '' }],   // alltid minst én rad i single-modus
  credit: '',
};

const MAX_GALLERY = 6;

function setStatus(msg, isError) {
  els.status.textContent = msg || '';
  els.status.style.color = isError ? '#FFB4B4' : '#fff';
}

function isValidImageUrl(s) {
  if (!s) return false;
  try {
    const u = new URL(s);
    return u.protocol === 'http:' || u.protocol === 'https:';
  } catch (e) { return false; }
}

function escapeHtml(s) {
  return String(s == null ? '' : s).replace(/[<>&"']/g, c => ({
    '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&#39;',
  }[c]));
}

// ---------- Rendering: sidebar image-liste ----------
function renderImageList() {
  els.imageList.innerHTML = '';
  state.images.forEach((img, i) => {
    const row = document.createElement('div');
    row.className = 'image-list__row';

    const num = document.createElement('div');
    num.className = 'image-list__num';
    num.textContent = String(i + 1);

    const urlInput = document.createElement('input');
    urlInput.type = 'text';
    urlInput.className = 'url-row__input';
    urlInput.placeholder = 'https://faktisk.no/uploads/…';
    urlInput.value = img.url || '';
    urlInput.spellcheck = false;
    urlInput.autocomplete = 'off';
    urlInput.addEventListener('input', () => {
      state.images[i].url = urlInput.value.trim();
      renderPreview();
      updateExportButtons();
      scheduleSaveState();
    });

    const del = document.createElement('button');
    del.type = 'button';
    del.className = 'image-list__del';
    del.title = 'Fjern bildet';
    del.textContent = '×';
    del.disabled = state.mode === 'single' || state.images.length <= 1;
    del.style.visibility = (state.mode === 'gallery' && state.images.length > 1) ? 'visible' : 'hidden';
    del.addEventListener('click', () => {
      state.images.splice(i, 1);
      renderImageList();
      renderPreview();
      updateExportButtons();
      scheduleSaveState();
    });

    row.appendChild(num);
    row.appendChild(urlInput);
    row.appendChild(del);

    // Caption-input under URL (spenner over kolonne 2-3)
    const capInput = document.createElement('input');
    capInput.type = 'text';
    capInput.className = 'caption-input caption-input--single image-list__caption';
    capInput.placeholder = state.mode === 'gallery' ? 'Bildetekst for dette bildet (valgfri)' : 'Bildetekst (valgfri)';
    capInput.value = img.caption || '';
    capInput.spellcheck = true;
    capInput.addEventListener('input', () => {
      state.images[i].caption = capInput.value;
      renderPreview();
      scheduleSaveState();
    });
    row.appendChild(capInput);

    els.imageList.appendChild(row);
  });

  // Vis/skjul "+ Legg til bilde"-knapp avhengig av modus og antall
  if (state.mode === 'gallery' && state.images.length < MAX_GALLERY) {
    els.addImageBtn.style.display = '';
  } else {
    els.addImageBtn.style.display = 'none';
  }
}

// ---------- Studio-preview (canvas) ----------
function renderPreview() {
  const validImages = state.images.filter(img => isValidImageUrl(img.url));
  if (validImages.length === 0) {
    els.emptyState.style.display = '';
    els.preview.style.display = 'none';
    return;
  }
  els.emptyState.style.display = 'none';
  els.preview.style.display = '';

  const isGallery = state.mode === 'gallery';
  const gridClass = isGallery ? 'popup-preview__grid--gallery' : 'popup-preview__grid--single';

  els.preview.innerHTML = `
    <div class="popup-preview__label">Slik vises ${isGallery ? 'galleriet' : 'bildet'} i artikkelen</div>
    <div class="popup-preview__grid ${gridClass}">
      ${validImages.map((img, i) => `
        <div class="popup-preview__thumb" data-i="${i}">
          <img src="${escapeHtml(img.url)}" alt="${escapeHtml(img.caption || '')}">
          <div class="popup-preview__thumb__icon" title="Forhåndsvis pop-up">
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M15 3h6v6h-2V6.41l-4.29 4.3-1.42-1.42L17.59 5H15V3zM5 15H3v6h6v-2H6.41l4.3-4.29-1.42-1.42L5 17.59V15z"/>
            </svg>
          </div>
        </div>
      `).join('')}
    </div>
    <div class="popup-preview__label" style="opacity:0.5;">Klikk en thumbnail for å forhåndsvise pop-up-en</div>
  `;

  els.preview.querySelectorAll('.popup-preview__thumb').forEach(thumb => {
    thumb.addEventListener('click', () => {
      const i = +thumb.dataset.i;
      openStudioLightbox(validImages, i);
    });
  });
}

// ---------- Studio-intern lightbox (forhåndsvisning) ----------
let studioLB = null;
function openStudioLightbox(images, startIdx) {
  closeStudioLightbox();
  let idx = startIdx;
  const credit = state.credit.trim();

  const lb = document.createElement('div');
  lb.className = 'studio-lightbox';
  lb.innerHTML = `
    <button class="studio-lightbox__close" aria-label="Lukk">✕</button>
    ${images.length > 1 ? `
      <button class="studio-lightbox__nav studio-lightbox__nav--prev" aria-label="Forrige">
        <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/></svg>
      </button>
      <button class="studio-lightbox__nav studio-lightbox__nav--next" aria-label="Neste">
        <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/></svg>
      </button>
    ` : ''}
    <img alt="">
    <div class="studio-lightbox__caption"></div>
  `;
  document.body.appendChild(lb);
  studioLB = lb;

  const imgEl = lb.querySelector('img');
  const capEl = lb.querySelector('.studio-lightbox__caption');
  function show(i) {
    idx = (i + images.length) % images.length;
    imgEl.src = images[idx].url;
    const cap = images[idx].caption || '';
    let html = '';
    if (cap) html += escapeHtml(cap);
    if (credit) html += (cap ? '<br>' : '') + '<span style="opacity:0.7;">Foto: ' + escapeHtml(credit) + '</span>';
    capEl.innerHTML = html;
  }
  show(idx);

  lb.querySelector('.studio-lightbox__close').addEventListener('click', closeStudioLightbox);
  const prev = lb.querySelector('.studio-lightbox__nav--prev');
  const next = lb.querySelector('.studio-lightbox__nav--next');
  if (prev) prev.addEventListener('click', () => show(idx - 1));
  if (next) next.addEventListener('click', () => show(idx + 1));
  lb.addEventListener('click', (e) => {
    if (e.target === lb) closeStudioLightbox();
  });
  function keyHandler(e) {
    if (e.key === 'Escape') closeStudioLightbox();
    else if (e.key === 'ArrowLeft' && images.length > 1) show(idx - 1);
    else if (e.key === 'ArrowRight' && images.length > 1) show(idx + 1);
  }
  document.addEventListener('keydown', keyHandler);
  lb._keyHandler = keyHandler;
}
function closeStudioLightbox() {
  if (!studioLB) return;
  if (studioLB._keyHandler) document.removeEventListener('keydown', studioLB._keyHandler);
  studioLB.remove();
  studioLB = null;
}

// ---------- Embed-snippet ----------
function buildEmbedSnippet() {
  const validImages = state.images.filter(img => isValidImageUrl(img.url));
  if (validImages.length === 0) return '';

  const id = 'fpu-' + Math.random().toString(36).slice(2, 8);
  const isGallery = state.mode === 'gallery' && validImages.length > 1;
  const credit = state.credit.trim();
  const creditHtml = credit ? `<span class="fpu-${id}-credit">Foto: ${escapeHtml(credit)}</span>` : '';

  // Bygg JSON-data som lightboxen kan lese
  const imgData = validImages.map(img => ({
    src: img.url,
    cap: (img.caption || '').trim(),
  }));
  const imgDataJson = JSON.stringify(imgData).replace(/</g, '\\u003c');

  // Thumbnail-HTML
  const thumbsHtml = validImages.map((img, i) => `
    <button class="fpu-${id}-thumb" type="button" data-i="${i}" aria-label="Åpne bilde i pop-up">
      <img src="${escapeHtml(img.src || img.url)}" alt="${escapeHtml(img.cap || img.caption || '')}" loading="lazy">
      <span class="fpu-${id}-thumb-icon" aria-hidden="true">
        <svg viewBox="0 0 24 24"><path d="M15 3h6v6h-2V6.41l-4.29 4.3-1.42-1.42L17.59 5H15V3zM5 15H3v6h6v-2H6.41l4.3-4.29-1.42-1.42L5 17.59V15z"/></svg>
      </span>
    </button>
  `).join('');

  return `<!-- ============================================
     FAKTISK · POP UP
     Klikk bildet for å åpne stort i pop-up.
     ============================================ -->
<style>
  .fpu-${id}-wrap { container-type: inline-size; }
  .fpu-${id}-grid {
    display: grid;
    gap: clamp(10px, 1.4cqw, 18px);
    ${isGallery
      ? 'grid-template-columns: repeat(auto-fill, minmax(min(180px, 100%), 1fr));'
      : 'grid-template-columns: 1fr;'}
  }
  .fpu-${id}-thumb {
    position: relative;
    display: block;
    width: 100%;
    padding: 0;
    background: #fff;
    border: 3px solid #D9D9D9;
    border-radius: 10px;
    overflow: hidden;
    cursor: zoom-in;
    aspect-ratio: 4 / 3;
    transition: transform 0.18s ease, box-shadow 0.18s ease, border-color 0.18s ease;
    box-shadow: 0 1px 4px rgba(0,0,0,0.05);
  }
  .fpu-${id}-thumb:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 18px rgba(0,0,0,0.12);
    border-color: #BFBFBF;
  }
  .fpu-${id}-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
  }
  .fpu-${id}-thumb-icon {
    position: absolute;
    bottom: 10px;
    right: 10px;
    width: 32px;
    height: 32px;
    background: rgba(0,0,0,0.72);
    color: #fff;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.18s;
  }
  .fpu-${id}-thumb:hover .fpu-${id}-thumb-icon { opacity: 1; }
  .fpu-${id}-thumb-icon svg { width: 16px; height: 16px; fill: currentColor; }

  /* Lightbox / pop-up */
  .fpu-${id}-lb {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.88);
    z-index: 9999;
    display: none;
    align-items: center;
    justify-content: center;
    padding: 40px 24px;
    flex-direction: column;
    gap: 16px;
    animation: fpu-${id}-in 0.18s ease-out;
  }
  .fpu-${id}-lb.is-open { display: flex; }
  @keyframes fpu-${id}-in { from { opacity: 0; } to { opacity: 1; } }
  .fpu-${id}-lb__img-wrap {
    max-width: min(1200px, 92vw);
    max-height: 78vh;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .fpu-${id}-lb img {
    max-width: 100%;
    max-height: 78vh;
    object-fit: contain;
    display: block;
    border-radius: 4px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.5);
  }
  .fpu-${id}-lb__caption {
    color: #fff;
    font-family: "Haas Grot Text 55 Roman", "Helvetica Neue", Helvetica, Arial, sans-serif;
    font-size: 15px;
    max-width: 720px;
    text-align: center;
    line-height: 1.5;
    margin: 0;
    padding: 0 8px;
  }
  .fpu-${id}-credit {
    display: block;
    opacity: 0.65;
    font-size: 13px;
    margin-top: 6px;
  }
  .fpu-${id}-lb__close,
  .fpu-${id}-lb__nav {
    position: absolute;
    background: rgba(255,255,255,0.15);
    border: 0;
    color: #fff;
    cursor: pointer;
    backdrop-filter: blur(4px);
    transition: background 0.15s;
    font-family: inherit;
  }
  .fpu-${id}-lb__close:hover,
  .fpu-${id}-lb__nav:hover { background: rgba(255,255,255,0.28); }
  .fpu-${id}-lb__close {
    top: 16px;
    right: 16px;
    width: 44px;
    height: 44px;
    border-radius: 50%;
    font-size: 22px;
    line-height: 1;
  }
  .fpu-${id}-lb__nav {
    top: 50%;
    transform: translateY(-50%);
    width: 52px;
    height: 52px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .fpu-${id}-lb__nav svg { width: 24px; height: 24px; fill: currentColor; }
  .fpu-${id}-lb__nav--prev { left: 16px; }
  .fpu-${id}-lb__nav--next { right: 16px; }

  @media (max-width: 600px) {
    .fpu-${id}-lb { padding: 20px 12px; }
    .fpu-${id}-lb__nav { width: 44px; height: 44px; }
    .fpu-${id}-lb__close { width: 40px; height: 40px; top: 10px; right: 10px; }
  }
</style>

<div class="fpu-${id}-wrap">
  <div class="fpu-${id}-grid">${thumbsHtml}
  </div>
</div>

<div class="fpu-${id}-lb" id="${id}-lb" role="dialog" aria-modal="true" aria-label="Bilde-pop-up">
  <button class="fpu-${id}-lb__close" id="${id}-close" type="button" aria-label="Lukk">✕</button>
  ${isGallery ? `
  <button class="fpu-${id}-lb__nav fpu-${id}-lb__nav--prev" id="${id}-prev" type="button" aria-label="Forrige bilde">
    <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/></svg>
  </button>
  <button class="fpu-${id}-lb__nav fpu-${id}-lb__nav--next" id="${id}-next" type="button" aria-label="Neste bilde">
    <svg viewBox="0 0 24 24" aria-hidden="true"><path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/></svg>
  </button>` : ''}
  <div class="fpu-${id}-lb__img-wrap">
    <img id="${id}-img" alt="">
  </div>
  <p class="fpu-${id}-lb__caption" id="${id}-cap"></p>
</div>

<script>
(function(){
  var data = ${imgDataJson};
  var credit = ${JSON.stringify(credit)};
  var idx = 0;
  var lb = document.getElementById('${id}-lb');
  var img = document.getElementById('${id}-img');
  var cap = document.getElementById('${id}-cap');
  var closeBtn = document.getElementById('${id}-close');
  var prev = document.getElementById('${id}-prev');
  var next = document.getElementById('${id}-next');
  function esc(s){ return String(s).replace(/[<>&"]/g, function(c){ return ({'<':'&lt;','>':'&gt;','&':'&amp;','"':'&quot;'}[c]); }); }
  function show(i){
    if (!data.length) return;
    idx = (i + data.length) % data.length;
    img.src = data[idx].src;
    img.alt = data[idx].cap || '';
    var html = '';
    if (data[idx].cap) html += esc(data[idx].cap);
    if (credit) html += (data[idx].cap ? '<br>' : '') + '<span class="fpu-${id}-credit">Foto: ' + esc(credit) + '</span>';
    cap.innerHTML = html;
  }
  function open(i){
    show(i);
    lb.classList.add('is-open');
    document.body.style.overflow = 'hidden';
  }
  function close(){
    lb.classList.remove('is-open');
    document.body.style.overflow = '';
  }
  var thumbs = document.querySelectorAll('.fpu-${id}-thumb');
  thumbs.forEach(function(t){
    t.addEventListener('click', function(){ open(+t.dataset.i); });
  });
  closeBtn.addEventListener('click', close);
  if (prev) prev.addEventListener('click', function(){ show(idx - 1); });
  if (next) next.addEventListener('click', function(){ show(idx + 1); });
  lb.addEventListener('click', function(e){
    if (e.target === lb) close();
  });
  document.addEventListener('keydown', function(e){
    if (!lb.classList.contains('is-open')) return;
    if (e.key === 'Escape') close();
    else if (e.key === 'ArrowLeft' && data.length > 1) show(idx - 1);
    else if (e.key === 'ArrowRight' && data.length > 1) show(idx + 1);
  });
})();
</script>
`;
}

// ---------- Mode toggle ----------
function setMode(mode) {
  if (state.mode === mode) return;
  state.mode = mode;
  els.modeSingleBtn.classList.toggle('is-active', mode === 'single');
  els.modeGalleryBtn.classList.toggle('is-active', mode === 'gallery');
  els.imagesLabel.textContent = mode === 'gallery' ? 'Bilder' : 'Bilde';
  els.galleryHint.style.display = mode === 'gallery' ? '' : 'none';

  if (mode === 'single') {
    // Behold første bilde, dropp resten
    state.images = state.images.slice(0, 1);
    if (state.images.length === 0) state.images = [{ url: '', caption: '' }];
  } else {
    // Sørg for at vi har minst 2 rader så det er åpenbart at det er galleri
    if (state.images.length < 2) {
      while (state.images.length < 2) state.images.push({ url: '', caption: '' });
    }
  }
  renderImageList();
  renderPreview();
  updateExportButtons();
  scheduleSaveState();
}

els.modeSingleBtn.addEventListener('click', () => setMode('single'));
els.modeGalleryBtn.addEventListener('click', () => setMode('gallery'));
els.addImageBtn.addEventListener('click', () => {
  if (state.images.length >= MAX_GALLERY) return;
  state.images.push({ url: '', caption: '' });
  renderImageList();
  renderPreview();
  scheduleSaveState();
});

// ---------- Copy embed ----------
function updateExportButtons() {
  const validCount = state.images.filter(img => isValidImageUrl(img.url)).length;
  els.copyEmbed.disabled = validCount === 0;
}

els.copyEmbed.addEventListener('click', async () => {
  const snippet = buildEmbedSnippet();
  if (!snippet) { setStatus('Legg til minst ett gyldig bilde.', true); return; }
  try {
    await window.faktisk.copyToClipboard(snippet);
    const orig = els.copyEmbed.textContent;
    els.copyEmbed.textContent = '✅ Kopiert!';
    setStatus('Embed-koden er kopiert.');
    setTimeout(() => { els.copyEmbed.textContent = orig; }, 2000);
  } catch (e) {
    setStatus('Kunne ikke kopiere: ' + e.message, true);
  }
});

// ---------- Photographer input ----------
els.photographer.addEventListener('input', () => {
  state.credit = els.photographer.value;
  scheduleSaveState();
});

// ---------- Topbar ----------
els.back.addEventListener('click', async () => { await window.faktisk.goHome(); });
els.full.addEventListener('click', async () => { await window.faktisk.toggleFullscreen(); });
els.openLabrador.addEventListener('click', async () => {
  await window.faktisk.openExternal('https://labrador.faktisk.no/settings/upload-file');
});

// ---------- Save / load state ----------
let isRestoring = false;
function serializeState() {
  return {
    mode: state.mode,
    images: state.images.map(img => ({ url: img.url, caption: img.caption })),
    credit: state.credit,
  };
}
async function applyState(saved) {
  if (!saved) return;
  isRestoring = true;
  try {
    if (saved.mode === 'single' || saved.mode === 'gallery') {
      state.mode = saved.mode;
      els.modeSingleBtn.classList.toggle('is-active', state.mode === 'single');
      els.modeGalleryBtn.classList.toggle('is-active', state.mode === 'gallery');
      els.imagesLabel.textContent = state.mode === 'gallery' ? 'Bilder' : 'Bilde';
      els.galleryHint.style.display = state.mode === 'gallery' ? '' : 'none';
    }
    if (Array.isArray(saved.images) && saved.images.length > 0) {
      state.images = saved.images.map(img => ({
        url: typeof img.url === 'string' ? img.url : '',
        caption: typeof img.caption === 'string' ? img.caption : '',
      })).slice(0, MAX_GALLERY);
    }
    if (typeof saved.credit === 'string') {
      state.credit = saved.credit;
      els.photographer.value = saved.credit;
    }
    renderImageList();
    renderPreview();
    updateExportButtons();
  } finally {
    isRestoring = false;
  }
}
let saveTimer = null;
function scheduleSaveState() {
  if (isRestoring) return;
  clearTimeout(saveTimer);
  saveTimer = setTimeout(() => {
    window.faktisk.stateSave(PLUGIN_ID, serializeState()).catch(console.error);
  }, 400);
}

// ---------- Project list ----------
async function refreshProjectList() {
  try {
    const res = await window.faktisk.projectList(PLUGIN_ID);
    if (!res.ok) return;
    const sel = els.projectSelect;
    while (sel.options.length > 1) sel.remove(1);
    res.projects.forEach(p => {
      const opt = document.createElement('option');
      opt.value = p.fileId;
      opt.textContent = p.name;
      sel.appendChild(opt);
    });
  } catch (e) { console.error(e); }
}

els.saveProject.addEventListener('click', async () => {
  const firstCap = (state.images.find(i => i.caption) || {}).caption || '';
  const defaultName = firstCap.slice(0, 40).trim()
    || `Pop up ${new Date().toLocaleDateString('no')}`;
  const name = await window.faktiskDialog.prompt('Lagre prosjekt som:', defaultName);
  if (!name || !name.trim()) return;
  const res = await window.faktisk.projectSave(PLUGIN_ID, name.trim(), serializeState());
  if (res.ok) {
    setStatus('Lagret: «' + res.name + '».');
    await refreshProjectList();
  } else {
    setStatus('Kunne ikke lagre: ' + (res.error || 'ukjent feil'), true);
  }
});

els.projectSelect.addEventListener('change', async () => {
  const fileId = els.projectSelect.value;
  if (!fileId) return;
  const res = await window.faktisk.projectLoad(PLUGIN_ID, fileId);
  if (res.ok && res.state) {
    setStatus('Åpner «' + res.name + '»…');
    await applyState(res.state);
    setStatus('Åpnet «' + res.name + '».');
  }
});

// ---------- Init ----------
(async function init() {
  renderImageList();
  renderPreview();
  updateExportButtons();
  await refreshProjectList();
  const pending = localStorage.getItem('faktisk-pending-project');
  if (pending) {
    try {
      const { pluginId, fileId } = JSON.parse(pending);
      localStorage.removeItem('faktisk-pending-project');
      if (pluginId === PLUGIN_ID) {
        const res = await window.faktisk.projectLoad(pluginId, fileId);
        if (res.ok && res.state) {
          await applyState(res.state);
          els.projectSelect.value = fileId;
          return;
        }
      }
    } catch (e) { console.error(e); }
  }
  try {
    const res = await window.faktisk.stateLoad(PLUGIN_ID);
    if (res.ok && res.state) await applyState(res.state);
  } catch (e) { console.error(e); }
})();

