  max-width: 720px;
}
.popup-preview__grid--single { grid-template-columns: 1fr; max-width: 520px; }
.popup-preview__grid--gallery {
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
}
.popup-preview__thumb {
  position: relative;
  background: #fff;
  border: 3px solid #D9D9D9;
  border-radius: 10px;
  overflow: hidden;
  aspect-ratio: 4 / 3;
  cursor: pointer;
  box-shadow: 0 2px 12px rgba(0,0,0,0.15);
  transition: transform 0.15s;
}
.popup-preview__thumb:hover { transform: translateY(-2px); }
.popup-preview__thumb img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}
.popup-preview__thumb__icon {
  position: absolute;
  bottom: 8px;
  right: 8px;
  width: 30px;
  height: 30px;
  background: rgba(0,0,0,0.7);
  color: #fff;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}
.popup-preview__thumb__icon svg { width: 16px; height: 16px; fill: currentColor; }

/* Studio-intern lightbox (preview når bruker klikker thumbnail i Studio) */
.studio-lightbox {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.88);
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
  flex-direction: column;
  gap: 16px;
}
.studio-lightbox img {
  max-width: min(1200px, 90vw);
  max-height: 80vh;
  object-fit: contain;
  display: block;
  border-radius: 4px;
}
.studio-lightbox__caption {
  color: #fff;
  font-family: var(--font-bold);
  font-size: 14px;
  max-width: 600px;
  text-align: center;
  line-height: 1.4;
}
.studio-lightbox__close {
  position: absolute;
  top: 16px;
  right: 16px;
  width: 40px;
  height: 40px;
  background: rgba(255,255,255,0.15);
  border: 0;
  border-radius: 50%;
  color: #fff;
  font-size: 22px;
  cursor: pointer;
  line-height: 1;
}
.studio-lightbox__close:hover { background: rgba(255,255,255,0.25); }
.studio-lightbox__nav {
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  width: 48px;
  height: 48px;
  background: rgba(255,255,255,0.15);
  border: 0;
  border-radius: 50%;
  color: #fff;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
}
.studio-lightbox__nav:hover { background: rgba(255,255,255,0.25); }
.studio-lightbox__nav--prev { left: 16px; }
.studio-lightbox__nav--next { right: 16px; }
.studio-lightbox__nav svg { width: 22px; height: 22px; fill: currentColor; }
